INSERT INTO "public"."raid_scenarios" ("id", "title", "requirement", "required_capacity", "required_interface", "correct_raid", "storage_efficiency", "total_usable", "fault_tolerance", "explanation", "drives") VALUES (1, 'Video Editing Workstation', 'A video production company needs the fastest possible read/write speeds for 4K footage editing. They maintain offsite backups so hardware data loss is acceptable.', '1 TB', 'NVMe', 'RAID 0', '100%', '2 TB', 'None', 'RAID 0 stripes data across both drives — blocks alternate between drives so reads and writes happen to both simultaneously, doubling throughput. NVMe drives are required for maximum speed (PCIe bus vs. SATA). Drives must match in capacity and interface; mixing sizes wastes space, mixing interfaces causes bottlenecks.', '[{"id":1,"iface":"NVMe","correct":true,"capacity":"1 TB"},{"id":2,"iface":"NVMe","correct":true,"capacity":"1 TB"},{"id":3,"iface":"NVMe","correct":false,"capacity":"2 TB"},{"id":4,"iface":"SATA SSD","correct":false,"capacity":"1 TB"},{"id":5,"iface":"NVMe","correct":false,"capacity":"512 GB"},{"id":6,"iface":"SATA HDD","correct":false,"capacity":"1 TB"},{"id":7,"iface":"NVMe","correct":false,"capacity":"256 GB"},{"id":8,"iface":"SATA SSD","correct":false,"capacity":"2 TB"},{"id":9,"iface":"NVMe","correct":false,"capacity":"4 TB"}]'), (2, 'Small Business File Server', 'A small accounting firm needs their file server to survive a single hard drive failure without data loss. Reliability matters more than peak speed.', '2 TB', 'SATA SSD', 'RAID 1', '50%', '2 TB', '1 drive', 'RAID 1 mirrors data identically across both drives. If one fails, the other holds a complete copy and the server keeps running. SATA SSD strikes the right balance of cost, reliability, and performance for a file server. Drives must match in capacity — a mismatch would limit usable space to the smaller drive.', '[{"id":1,"iface":"SATA SSD","correct":true,"capacity":"2 TB"},{"id":2,"iface":"SATA SSD","correct":true,"capacity":"2 TB"},{"id":3,"iface":"SATA SSD","correct":false,"capacity":"1 TB"},{"id":4,"iface":"SATA HDD","correct":false,"capacity":"2 TB"},{"id":5,"iface":"SATA SSD","correct":false,"capacity":"4 TB"},{"id":6,"iface":"NVMe","correct":false,"capacity":"2 TB"},{"id":7,"iface":"SATA SSD","correct":false,"capacity":"500 GB"},{"id":8,"iface":"SATA HDD","correct":false,"capacity":"1 TB"},{"id":9,"iface":"SATA SSD","correct":false,"capacity":"8 TB"}]'), (3, 'Web Application Server', 'A startup needs balanced read performance, storage efficiency, and single-drive fault tolerance for their web server. Budget-conscious — cost-effective drives preferred.', '2 TB', 'SATA SSD', 'RAID 5', '67%', '4 TB', '1 drive', 'RAID 5 stripes data with distributed parity across all 3 drives. Any single drive can fail and its data is rebuilt from the remaining two. Using identical 2 TB SATA SSDs ensures consistent performance and no wasted capacity. Mixing different capacities would force the array to use the smallest drive''s capacity for each.', '[{"id":1,"iface":"SATA SSD","correct":true,"capacity":"2 TB"},{"id":2,"iface":"SATA SSD","correct":true,"capacity":"2 TB"},{"id":3,"iface":"SATA SSD","correct":true,"capacity":"2 TB"},{"id":4,"iface":"SATA SSD","correct":false,"capacity":"1 TB"},{"id":5,"iface":"NVMe","correct":false,"capacity":"2 TB"},{"id":6,"iface":"SATA SSD","correct":false,"capacity":"4 TB"},{"id":7,"iface":"SATA HDD","correct":false,"capacity":"2 TB"},{"id":8,"iface":"SATA SSD","correct":false,"capacity":"500 GB"},{"id":9,"iface":"NVMe","correct":false,"capacity":"2 TB"}]'), (4, 'Financial Database Server', 'A bank''s transaction database must survive two simultaneous drive failures. High-capacity drives are required to handle IOPS-intensive workloads.', '4 TB', 'NVMe', 'RAID 6', '50%', '8 TB', '2 drives', 'RAID 6 uses two independent parity blocks per stripe — any two drives can fail simultaneously without data loss, critical for financial systems. NVMe is required to sustain high IOPS under heavy transaction loads. All four drives must be identical 4 TB NVMe; mismatched capacities reduce usable space, mismatched interfaces create bottlenecks at the slower drive.', '[{"id":1,"iface":"NVMe","correct":true,"capacity":"4 TB"},{"id":2,"iface":"NVMe","correct":true,"capacity":"4 TB"},{"id":3,"iface":"NVMe","correct":true,"capacity":"4 TB"},{"id":4,"iface":"NVMe","correct":true,"capacity":"4 TB"},{"id":5,"iface":"NVMe","correct":false,"capacity":"2 TB"},{"id":6,"iface":"SATA SSD","correct":false,"capacity":"4 TB"},{"id":7,"iface":"NVMe","correct":false,"capacity":"8 TB"},{"id":8,"iface":"SATA HDD","correct":false,"capacity":"4 TB"},{"id":9,"iface":"NVMe","correct":false,"capacity":"1 TB"},{"id":10,"iface":"NVMe","correct":false,"capacity":"512 GB"}]'), (5, 'Mission-Critical E-Commerce Platform', 'An online retailer needs high throughput and redundancy for 24/7 uptime. The array must survive at least one failure per mirrored pair.', '1 TB', 'NVMe', 'RAID 10', '50%', '2 TB', '1 per mirror pair', 'RAID 10 stripes across two mirrored NVMe pairs — delivering both read/write speed and redundancy. NVMe is essential for e-commerce peak-load performance. All four drives must be identical 1 TB NVMe; using different capacities would waste space on the larger drives, and mixing interfaces would limit the array to the slowest drive''s throughput.', '[{"id":1,"iface":"NVMe","correct":true,"capacity":"1 TB"},{"id":2,"iface":"NVMe","correct":true,"capacity":"1 TB"},{"id":3,"iface":"NVMe","correct":true,"capacity":"1 TB"},{"id":4,"iface":"NVMe","correct":true,"capacity":"1 TB"},{"id":5,"iface":"NVMe","correct":false,"capacity":"2 TB"},{"id":6,"iface":"SATA SSD","correct":false,"capacity":"1 TB"},{"id":7,"iface":"NVMe","correct":false,"capacity":"512 GB"},{"id":8,"iface":"SATA HDD","correct":false,"capacity":"1 TB"},{"id":9,"iface":"NVMe","correct":false,"capacity":"4 TB"},{"id":10,"iface":"NVMe","correct":false,"capacity":"256 GB"}]');